{
  "name": "Achievement System",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "AchievementSystem",
      "entity": {
        "name": "Achievement",
        "collection": "achievements",
        "fields": [
          {
            "name": "id",
            "type": "string",
            "primaryKey": true
          },
          {
            "name": "playerId",
            "type": "string",
            "required": true
          },
          {
            "name": "achievementId",
            "type": "string",
            "required": true
          },
          {
            "name": "title",
            "type": "string",
            "required": true
          },
          {
            "name": "description",
            "type": "string"
          },
          {
            "name": "icon",
            "type": "string"
          },
          {
            "name": "progress",
            "type": "number",
            "default": 0
          },
          {
            "name": "target",
            "type": "number",
            "required": true
          },
          {
            "name": "status",
            "type": "enum",
            "enum": [
              "locked",
              "in_progress",
              "unlocked"
            ]
          },
          {
            "name": "unlockedAt",
            "type": "timestamp"
          }
        ]
      },
      "traits": [
        {
          "name": "AchievementInteraction",
          "category": "interaction",
          "linkedEntity": "Achievement",
          "stateMachine": {
            "states": [
              {
                "name": "locked",
                "isInitial": true
              },
              {
                "name": "in_progress",
                "isInitial": false
              },
              {
                "name": "unlocked",
                "isInitial": false
              }
            ],
            "events": [
              {
                "key": "START",
                "name": "Start Progress"
              },
              {
                "key": "UPDATE",
                "name": "Update Progress"
              },
              {
                "key": "UNLOCK",
                "name": "Unlock"
              }
            ],
            "transitions": [
              {
                "from": "locked",
                "to": "in_progress",
                "event": "START",
                "effects": [
                  [
                    "set",
                    "status",
                    "in_progress"
                  ]
                ]
              },
              {
                "from": "in_progress",
                "to": "in_progress",
                "event": "UPDATE",
                "effects": [
                  [
                    "increment",
                    "progress",
                    "@payload.amount"
                  ]
                ]
              },
              {
                "from": "in_progress",
                "to": "unlocked",
                "event": "UNLOCK",
                "effects": [
                  [
                    "set",
                    "status",
                    "unlocked"
                  ],
                  [
                    "set",
                    "unlockedAt",
                    "@now"
                  ],
                  [
                    "notify",
                    "success",
                    "Achievement Unlocked: @entity.title"
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "AchievementPage",
          "path": "/achievements",
          "entity": "Achievement",
          "traits": [
            "AchievementInteraction"
          ]
        }
      ]
    }
  ]
}

