                "event": "RATE",
                "effects": [
                  [
                    "set",
                    "rating",
                    "@payload.rating"
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "ChatSessionPage",
          "path": "/chat_sessions",
          "entity": "ChatSession",
