}

{
  "name": "Stripe CreatePaymentIntent Demo",
  "version": "1.0.0",
  "orbitals": [
    {
      "name": "StripeIntegration",
      "entity": {
        "name": "Request",
        "runtime": true,
        "fields": [
          {
            "name": "id",
            "type": "string",
            "primaryKey": true
          },
          {
            "name": "status",
            "type": "enum",
            "enum": [
              "idle",
              "pending",
              "success",
              "error"
            ]
          },
          {
            "name": "input",
            "type": "object"
          },
          {
            "name": "result",
            "type": "object"
          },
          {
            "name": "error",
            "type": "string"
          }
        ]
      },
      "traits": [
        {
          "name": "StripeCreatePaymentIntent",
          "category": "integration",
          "linkedEntity": "Request",
          "stateMachine": {
            "states": [
              {
                "name": "idle",
                "isInitial": true
              },
              {
                "name": "pending"
              },
              {
                "name": "success"
              },
              {
                "name": "error"
              }
            ],
            "events": [
              {
                "key": "EXECUTE",
                "name": "Execute createPaymentIntent"
              },
              {
                "key": "SUCCESS",
                "name": "Success"
              },
              {
                "key": "ERROR",
                "name": "Error"
              },
              {
                "key": "RESET",
                "name": "Reset"
              }
            ],
            "transitions": [
              {
                "from": "idle",
                "to": "pending",
                "event": "EXECUTE",
                "effects": [
                  [
                    "set",
                    "status",
                    "pending"
                  ],
                  [
                    "set",
                    "input",
                    "@payload"
                  ],
                  [
                    "call-service",
                    "stripe",
                    "createPaymentIntent",
                    {
                      "amount": "@entity.amount",
                      "currency": "@payload.currency"
                    },
                    {
                      "onSuccess": "SUCCESS",
                      "onError": "ERROR"
                    }
                  ]
                ]
              },
              {
                "from": "pending",
                "to": "success",
                "event": "SUCCESS",
                "effects": [
                  [
                    "set",
                    "status",
                    "success"
                  ],
                  [
                    "set",
                    "result",
                    "@payload"
                  ],
                  [
                    "render-ui",
                    "main",
                    {
                      "type": "detail-panel",
                      "entity": "Request",
                      "title": "Result"
                    }
                  ]
                ]
              },
              {
                "from": "pending",
                "to": "error",
                "event": "ERROR",
                "effects": [
                  [
                    "set",
                    "status",
                    "error"
                  ],
                  [
                    "set",
                    "error",
                    "@payload.message"
                  ],
                  [
                    "notify",
                    "error",
                    "@payload.message"
                  ]
                ]
              },
              {
                "from": [
                  "success",
                  "error"
                ],
                "to": "idle",
                "event": "RESET",
                "effects": [
                  [
                    "set",
                    "status",
                    "idle"
                  ],
                  [
                    "set",
                    "result",
                    null
                  ],
                  [
                    "set",
                    "error",
                    null
                  ]
                ]
              }
            ]
          }
        }
      ],
      "pages": [
        {
          "name": "StripePage",
          "path": "/stripe",
          "entity": "Request",
          "traits": [
            "StripeCreatePaymentIntent"
          ]
        }
      ]
    }
  ]
}

